import{_ as t,o as r,c as l,ai as i}from"./chunks/framework.ampVZV4B.js";const g=JSON.parse('{"title":"Vue.js 开源项目","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/vue-projects.md","filePath":"open-source/vue-projects.md"}'),a={name:"open-source/vue-projects.md"};function u(s,e,o,h,n,b){return r(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="vue-js-开源项目" tabindex="-1">Vue.js 开源项目 <a class="header-anchor" href="#vue-js-开源项目" aria-label="Permalink to “Vue.js 开源项目”">​</a></h1><p>本页面精选了优秀的Vue.js开源项目，包括UI框架、组件库、工具、应用等。</p><h2 id="核心框架" tabindex="-1">核心框架 <a class="header-anchor" href="#核心框架" aria-label="Permalink to “核心框架”">​</a></h2><ul><li><p><strong>Vue.js</strong>：渐进式JavaScript框架</p><ul><li>GitHub: <a href="https://github.com/vuejs/vue" target="_blank" rel="noreferrer">https://github.com/vuejs/vue</a></li><li>特点: 响应式数据绑定、组件化、轻量级</li></ul></li><li><p><strong>Vue 3</strong>：最新版本</p><ul><li>GitHub: <a href="https://github.com/vuejs/core" target="_blank" rel="noreferrer">https://github.com/vuejs/core</a></li><li>新特性: Composition API、更好的TypeScript支持</li></ul></li></ul><h2 id="ui-框架与组件库" tabindex="-1">UI 框架与组件库 <a class="header-anchor" href="#ui-框架与组件库" aria-label="Permalink to “UI 框架与组件库”">​</a></h2><h3 id="桌面端组件库" tabindex="-1">桌面端组件库 <a class="header-anchor" href="#桌面端组件库" aria-label="Permalink to “桌面端组件库”">​</a></h3><ul><li><p><strong>Element Plus</strong>：基于Vue 3的企业级组件库</p><ul><li>GitHub: <a href="https://github.com/element-plus/element-plus" target="_blank" rel="noreferrer">https://github.com/element-plus/element-plus</a></li><li>特点: 完整组件、国际化、主题定制</li></ul></li><li><p><strong>Ant Design Vue</strong>：Ant Design的Vue实现</p><ul><li>GitHub: <a href="https://github.com/vueComponent/ant-design-vue" target="_blank" rel="noreferrer">https://github.com/vueComponent/ant-design-vue</a></li><li>特点: 企业级设计、美观大方</li></ul></li><li><p><strong>Vant</strong>：轻量级移动端组件库</p><ul><li>GitHub: <a href="https://github.com/youzan/vant" target="_blank" rel="noreferrer">https://github.com/youzan/vant</a></li><li>特点: 移动优先、按需加载</li></ul></li><li><p><strong>Quasar</strong>：响应式Vue组件框架</p><ul><li>GitHub: <a href="https://github.com/quasarframework/quasar" target="_blank" rel="noreferrer">https://github.com/quasarframework/quasar</a></li><li>特点: 跨平台、Material Design</li></ul></li></ul><h3 id="移动端组件库" tabindex="-1">移动端组件库 <a class="header-anchor" href="#移动端组件库" aria-label="Permalink to “移动端组件库”">​</a></h3><ul><li><p><strong>Mint UI</strong>：Vue移动端组件库</p><ul><li>GitHub: <a href="https://github.com/ElemeFE/mint-ui" target="_blank" rel="noreferrer">https://github.com/ElemeFE/mint-ui</a></li><li>特点: 饿了么出品、移动端优化</li></ul></li><li><p><strong>Cube UI</strong>：滴滴移动端组件库</p><ul><li>GitHub: <a href="https://github.com/didi/cube-ui" target="_blank" rel="noreferrer">https://github.com/didi/cube-ui</a></li><li>特点: 丰富组件、性能优化</li></ul></li></ul><h2 id="路由与状态管理" tabindex="-1">路由与状态管理 <a class="header-anchor" href="#路由与状态管理" aria-label="Permalink to “路由与状态管理”">​</a></h2><h3 id="路由" tabindex="-1">路由 <a class="header-anchor" href="#路由" aria-label="Permalink to “路由”">​</a></h3><ul><li><p><strong>Vue Router</strong>：官方路由管理器</p><ul><li>GitHub: <a href="https://github.com/vuejs/vue-router" target="_blank" rel="noreferrer">https://github.com/vuejs/vue-router</a></li><li>功能: 路由映射、嵌套路由、路由守卫</li></ul></li><li><p><strong>Vue Router 4</strong>：Vue 3版本</p><ul><li>GitHub: <a href="https://github.com/vuejs/router" target="_blank" rel="noreferrer">https://github.com/vuejs/router</a></li><li>新特性: TypeScript支持、组合式API</li></ul></li></ul><h3 id="状态管理" tabindex="-1">状态管理 <a class="header-anchor" href="#状态管理" aria-label="Permalink to “状态管理”">​</a></h3><ul><li><p><strong>Pinia</strong>：Vue的状态管理库</p><ul><li>GitHub: <a href="https://github.com/vuejs/pinia" target="_blank" rel="noreferrer">https://github.com/vuejs/pinia</a></li><li>特点: TypeScript友好、直观API</li></ul></li><li><p><strong>Vuex</strong>：官方状态管理库</p><ul><li>GitHub: <a href="https://github.com/vuejs/vuex" target="_blank" rel="noreferrer">https://github.com/vuejs/vuex</a></li><li>功能: 集中式状态管理、插件系统</li></ul></li><li><p><strong>Vuex 4</strong>：Vue 3兼容版本</p><ul><li>GitHub: <a href="https://github.com/vuejs/vuex" target="_blank" rel="noreferrer">https://github.com/vuejs/vuex</a></li><li>特点: 更好的TypeScript支持</li></ul></li></ul><h2 id="开发工具" tabindex="-1">开发工具 <a class="header-anchor" href="#开发工具" aria-label="Permalink to “开发工具”">​</a></h2><h3 id="构建工具" tabindex="-1">构建工具 <a class="header-anchor" href="#构建工具" aria-label="Permalink to “构建工具”">​</a></h3><ul><li><p><strong>Vite</strong>：下一代前端构建工具</p><ul><li>GitHub: <a href="https://github.com/vitejs/vite" target="_blank" rel="noreferrer">https://github.com/vitejs/vite</a></li><li>特点: 快速启动、热重载、Vue优化</li></ul></li><li><p><strong>Vue CLI</strong>：官方脚手架工具</p><ul><li>GitHub: <a href="https://github.com/vuejs/vue-cli" target="_blank" rel="noreferrer">https://github.com/vuejs/vue-cli</a></li><li>功能: 项目脚手架、插件系统</li></ul></li><li><p><strong>VitePress</strong>：Vue驱动的静态站点生成器</p><ul><li>GitHub: <a href="https://github.com/vuejs/vitepress" target="_blank" rel="noreferrer">https://github.com/vuejs/vitepress</a></li><li>功能: 文档站点、Vue组件展示</li></ul></li></ul><h3 id="开发辅助" tabindex="-1">开发辅助 <a class="header-anchor" href="#开发辅助" aria-label="Permalink to “开发辅助”">​</a></h3><ul><li><p><strong>Vue DevTools</strong>：浏览器调试工具</p><ul><li>GitHub: <a href="https://github.com/vuejs/devtools" target="_blank" rel="noreferrer">https://github.com/vuejs/devtools</a></li><li>功能: 组件检查、状态调试、性能分析</li></ul></li><li><p><strong>Vue Loader</strong>：Vue单文件组件加载器</p><ul><li>GitHub: <a href="https://github.com/vuejs/vue-loader" target="_blank" rel="noreferrer">https://github.com/vuejs/vue-loader</a></li><li>功能: SFC编译、热重载</li></ul></li></ul><h2 id="工具库" tabindex="-1">工具库 <a class="header-anchor" href="#工具库" aria-label="Permalink to “工具库”">​</a></h2><h3 id="http客户端" tabindex="-1">HTTP客户端 <a class="header-anchor" href="#http客户端" aria-label="Permalink to “HTTP客户端”">​</a></h3><ul><li><strong>Axios</strong>：Promise-based HTTP客户端 <ul><li>GitHub: <a href="https://github.com/axios/axios" target="_blank" rel="noreferrer">https://github.com/axios/axios</a></li><li>功能: HTTP请求、拦截器</li></ul></li></ul><h3 id="表单处理" tabindex="-1">表单处理 <a class="header-anchor" href="#表单处理" aria-label="Permalink to “表单处理”">​</a></h3><ul><li><p><strong>VeeValidate</strong>：表单验证库</p><ul><li>GitHub: <a href="https://github.com/logaretm/vee-validate" target="_blank" rel="noreferrer">https://github.com/logaretm/vee-validate</a></li><li>功能: 声明式验证、自定义规则</li></ul></li><li><p><strong>Vue Formulate</strong>：Vue表单框架</p><ul><li>GitHub: <a href="https://github.com/wearebraid/vue-formulate" target="_blank" rel="noreferrer">https://github.com/wearebraid/vue-formulate</a></li><li>功能: 智能表单、文件上传</li></ul></li></ul><h3 id="图表库" tabindex="-1">图表库 <a class="header-anchor" href="#图表库" aria-label="Permalink to “图表库”">​</a></h3><ul><li><p><strong>Vue Chart.js</strong>：Chart.js的Vue封装</p><ul><li>GitHub: <a href="https://github.com/apertureless/vue-chartjs" target="_blank" rel="noreferrer">https://github.com/apertureless/vue-chartjs</a></li><li>功能: 响应式图表、多种图表类型</li></ul></li><li><p><strong>ECharts for Vue</strong>：百度ECharts的Vue组件</p><ul><li>GitHub: <a href="https://github.com/ecomfe/vue-echarts" target="_blank" rel="noreferrer">https://github.com/ecomfe/vue-echarts</a></li><li>功能: 丰富的图表类型、交互功能</li></ul></li></ul><h3 id="其他工具" tabindex="-1">其他工具 <a class="header-anchor" href="#其他工具" aria-label="Permalink to “其他工具”">​</a></h3><ul><li><p><strong>VueUse</strong>：Vue组合式函数集合</p><ul><li>GitHub: <a href="https://github.com/vueuse/vueuse" target="_blank" rel="noreferrer">https://github.com/vueuse/vueuse</a></li><li>功能: 实用组合函数、传感器、动画</li></ul></li><li><p><strong>Vue I18n</strong>：国际化插件</p><ul><li>GitHub: <a href="https://github.com/kazupon/vue-i18n" target="_blank" rel="noreferrer">https://github.com/kazupon/vue-i18n</a></li><li>功能: 多语言支持、日期格式化</li></ul></li></ul><h2 id="应用项目" tabindex="-1">应用项目 <a class="header-anchor" href="#应用项目" aria-label="Permalink to “应用项目”">​</a></h2><h3 id="后台管理系统" tabindex="-1">后台管理系统 <a class="header-anchor" href="#后台管理系统" aria-label="Permalink to “后台管理系统”">​</a></h3><ul><li><p><strong>vue-element-admin</strong>：基于Element UI的后台管理系统</p><ul><li>GitHub: <a href="https://github.com/PanJiaChen/vue-element-admin" target="_blank" rel="noreferrer">https://github.com/PanJiaChen/vue-element-admin</a></li><li>功能: 用户管理、权限控制、动态路由</li></ul></li><li><p><strong>vue-admin-beautiful</strong>：漂亮的后台管理系统</p><ul><li>GitHub: <a href="https://github.com/chuzhixin/vue-admin-beautiful" target="_blank" rel="noreferrer">https://github.com/chuzhixin/vue-admin-beautiful</a></li><li>特点: 美观界面、丰富组件</li></ul></li><li><p><strong>D2Admin</strong>：优雅的后台管理系统</p><ul><li>GitHub: <a href="https://github.com/d2-projects/d2-admin" target="_blank" rel="noreferrer">https://github.com/d2-projects/d2-admin</a></li><li>功能: 模块化、主题切换</li></ul></li></ul><h3 id="博客-cms系统" tabindex="-1">博客/CMS系统 <a class="header-anchor" href="#博客-cms系统" aria-label="Permalink to “博客/CMS系统”">​</a></h3><ul><li><p><strong>VuePress</strong>：Vue驱动的静态站点生成器</p><ul><li>GitHub: <a href="https://github.com/vuejs/vuepress" target="_blank" rel="noreferrer">https://github.com/vuejs/vuepress</a></li><li>功能: Markdown写作、主题系统</li></ul></li><li><p><strong>Gridsome</strong>：Vue.js静态站点生成器</p><ul><li>GitHub: <a href="https://github.com/gridsome/gridsome" target="_blank" rel="noreferrer">https://github.com/gridsome/gridsome</a></li><li>功能: GraphQL数据层、PWA支持</li></ul></li></ul><h3 id="电商应用" tabindex="-1">电商应用 <a class="header-anchor" href="#电商应用" aria-label="Permalink to “电商应用”">​</a></h3><ul><li><strong>vue-shop</strong>：Vue电商应用 <ul><li>GitHub: <a href="https://github.com/vuestorefront/vue-storefront" target="_blank" rel="noreferrer">https://github.com/vuestorefront/vue-storefront</a></li><li>功能: 电商前端、PWA、离线支持</li></ul></li></ul><h3 id="聊天应用" tabindex="-1">聊天应用 <a class="header-anchor" href="#聊天应用" aria-label="Permalink to “聊天应用”">​</a></h3><ul><li><strong>Vue Chat</strong>：实时聊天应用 <ul><li>GitHub: <a href="https://github.com/vuejsdevelopers/vue-chat" target="_blank" rel="noreferrer">https://github.com/vuejsdevelopers/vue-chat</a></li><li>功能: 实时通信、表情支持</li></ul></li></ul><h2 id="服务端渲染" tabindex="-1">服务端渲染 <a class="header-anchor" href="#服务端渲染" aria-label="Permalink to “服务端渲染”">​</a></h2><ul><li><p><strong>Nuxt.js</strong>：Vue的服务端渲染框架</p><ul><li>GitHub: <a href="https://github.com/nuxt/nuxt.js" target="_blank" rel="noreferrer">https://github.com/nuxt/nuxt.js</a></li><li>功能: SSR、静态生成、模块系统</li></ul></li><li><p><strong>Nuxt 3</strong>：下一代Nuxt</p><ul><li>GitHub: <a href="https://github.com/nuxt/framework" target="_blank" rel="noreferrer">https://github.com/nuxt/framework</a></li><li>新特性: Vue 3支持、更好的性能</li></ul></li></ul><h2 id="移动端框架" tabindex="-1">移动端框架 <a class="header-anchor" href="#移动端框架" aria-label="Permalink to “移动端框架”">​</a></h2><ul><li><p><strong>Vue Native</strong>：使用Vue构建原生移动应用</p><ul><li>GitHub: <a href="https://github.com/GeekyAnts/vue-native-core" target="_blank" rel="noreferrer">https://github.com/GeekyAnts/vue-native-core</a></li><li>功能: React Native + Vue语法</li></ul></li><li><p><strong>Weex</strong>：跨平台移动端框架</p><ul><li>GitHub: <a href="https://github.com/apache/incubator-weex" target="_blank" rel="noreferrer">https://github.com/apache/incubator-weex</a></li><li>功能: 写一次，多端运行</li></ul></li></ul>',41)])])}const c=t(a,[["render",u]]);export{g as __pageData,c as default};
